import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets
import groovy.json.*

// Read flow file content
def flowFile = session.get()
if (!flowFile) return

flowFile = session.write(flowFile, { inputStream, outputStream ->
    def text = IOUtils.toString(inputStream, StandardCharsets.UTF_8)
    def json = new JsonSlurper().parseText(text)

    // Modify JSON array
    def modified = json.collect { record ->
        // Create full_name
        record.full_name = "${record.first_name} ${record.last_name}"


        // Remove phone number
        record.remove("phone")

        return record
    }

    // Write back modified JSON
    def outputJson = JsonOutput.prettyPrint(JsonOutput.toJson(modified))
    outputStream.write(outputJson.getBytes(StandardCharsets.UTF_8))
} as StreamCallback)

session.transfer(flowFile, REL_SUCCESS)
